#include <bits/stdc++.h>
using namespace std;vector<vector<pair<int,long long>>>g;
pair<long long,int> far(int s,int n){vector<long long>d(n+1,-1);queue<int>q;q.push(s);d[s]=0;long long mx=0;int idx=s;while(!q.empty()){int u=q.front();q.pop();for(auto[v,w]:g[u])if(d[v]<0){d[v]=d[u]+w;if(d[v]>mx){mx=d[v];idx=v;}q.push(v);}}return{mx,idx};}
int main(){int n;scanf("%d",&n);g.assign(n+1,{});for(int i=0;i<n;i++){int u;scanf("%d",&u);int v;while(scanf("%d",&v)&&v!=-1){long long w;scanf("%lld",&w);g[u].push_back({v,w});}}auto a=far(1,n);auto b=far(a.second,n);printf("%lld\n",b.first);}
